<template>
    <div>
        <el-form inline v-for="(i, index) in items" :key="index">
            <el-form-item label="总价">
                <el-input v-model="i.total"/>
            </el-form-item>
            <el-form-item label="期数">
                <el-input v-model="i.period"/>
            </el-form-item>
            <el-form-item label="年化利率%">
                <el-input v-model="i.rate"/>
            </el-form-item>
            <el-form-item label="现值">
                <el-input :value="value(i)" disabled/>
                <small>{{(i.total-value(i)).toFixed(2)}}</small>
            </el-form-item>
        </el-form>
        <el-button icon="el-icon-plus" @click="items.push({})">增加一行</el-button>
    </div>
</template>
<script>
    export default {
        data() {
            return {
                items: [{}]
            }
        },
        methods: {
            value(o) {
                let 每期年金 = o.total / o.period;
                let 每期利率 = o.rate / 1200;
                return (每期年金 / 每期利率 * (1 - Math.pow(1 + 每期利率, -o.period))).toFixed(2);
            }
        },
    }
</script>
